import{_ as o,o as a,c as i,ag as t}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Аліаси Python | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди Python. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси Python | Dotfiles","description":"Короткі команди Python. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси Python | Dotfiles preview","canonical":"/uk/aliases/python/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси Python","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/python/"},"headers":[],"relativePath":"uk/aliases/python/index.md","filePath":"uk/aliases/python/index.md","lastUpdated":1773010926000}'),l={name:"uk/aliases/python/index.md"};function d(c,e,n,p,s,r){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="аліаси-python" tabindex="-1">Аліаси Python <a class="header-anchor" href="#аліаси-python" aria-label="Permalink to &quot;Аліаси Python&quot;">​</a></h1><p>Короткі команди Python.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 44</li><li>Допоміжні функції: 2</li><li>Файли джерел: 1</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>black</code> → <code>&#39;python -m black&#39; # Форматування коду з black</code></li><li><code>deact</code> → <code>&#39;deactivate&#39; # Деактивація venv</code></li><li><code>ipy</code> → <code>&#39;ipython&#39; # Інтерактивна оболонка Python</code></li><li><code>lint</code> → <code>&#39;pylint&#39; # Лінтинг коду</code></li><li><code>mkvenv</code> → <code>&#39;python -m venv .venv&#39; # Створити .venv у поточному каталозі</code></li><li><code>mkvenvlocal</code> → <code>&#39;python -m venv ./venv&#39; # Створити ./venv у поточному каталозі</code></li><li><code>mypy</code> → <code>&#39;python -m mypy&#39; # Статична перевірка типів</code></li><li><code>pep8</code> → <code>&#39;autopep8&#39; # Форматування коду</code></li><li><code>pipf</code> → <code>&#39;pip freeze&#39; # Показати заморожені залежності</code></li><li><code>pipi</code> → <code>&#39;pip install&#39; # Встановити пакети</code></li><li><code>pipl</code> → <code>&#39;pip list&#39; # Список встановлених пакетів</code></li><li><code>pipout</code> → <code>&#39;pip freeze &gt; requirements.txt&#39; # Зберегти залежності</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const m=o(l,[["render",d]]);export{u as __pageData,m as default};
